def generate_evaluation_dataset_once() -> None:
    """Generate the fixed evaluation dataset once if it does not exist."""
    if EVALUATION_DATASET_PATH.exists():
        logger.info("Evaluation dataset already exists; skipping generation.")
        return

    try:
        logger.info("Evaluation dataset missing; starting background generation.")
        EVALUATION_DIR.mkdir(exist_ok=True)
        intervention_library = load_intervention_library()
        selected_students = select_evaluation_students()
        cases = [
            build_evaluation_case(
                case_id=f"case_{index:03d}",
                student=student,
                intervention_library=intervention_library,
            )
            for index, student in enumerate(selected_students, start=1)
        ]

        for case in cases:
            (EVALUATION_DIR / f"{case['case_id']}.md").write_text(
                render_evaluation_case_markdown(case),
                encoding="utf-8",
            )

        EVALUATION_DATASET_PATH.write_text(
            json.dumps(cases, indent=2, ensure_ascii=False),
            encoding="utf-8",
        )
        logger.info("Evaluation dataset generation complete.")
    except Exception:
        logger.exception("Evaluation dataset generation failed.")


